import React from 'react';
import Link from 'next/link';
import PersonIcon from '@mui/icons-material/Person';
import SearchIcon from '@mui/icons-material/Search';
import ShoppingCartIcon from '@mui/icons-material/ShoppingCart';
import FavoriteIcon from '@mui/icons-material/Favorite';
import styles from './Nav.module.css';

interface NavProps {} // Define props interface for potential future additions

const Nav: React.FC<NavProps> = () => {
  return (
    <div className={styles.NavContainer}>
      <h1 className={styles.HOne}>Bandage</h1>
      <div className={styles.ListItems}>
        <div className={styles.LinkLists}>
          <Link href="/" className={styles.linklist}>Home</Link>
          <Link href="/shop" className={styles.linklist}>Shop</Link>
          <Link href="/about" className={styles.linklist}>About</Link>
          <Link href="/blog" className={styles.linklist}>Blog</Link>
          <Link href="/contact" className={styles.linklist}>Contact</Link>
          <Link href="/pages" className={styles.linklist}>Pages</Link>
        </div>

        <div className={styles.RegisterForm}>
          <div className={styles.NavForms}>
            <PersonIcon className={styles.NavIconColors} />
            <Link href="/login" className={styles.linklistForm}>Login</Link>
             /
            <Link href="/register" className={styles.linklistForm}>Register</Link>
          </div>

          <div className={styles.NavIcons}>
            <SearchIcon className={styles.NavIconColors} />
            <ShoppingCartIcon className={styles.NavIconColors} />
            <FavoriteIcon className={styles.NavIconColors} />
          </div>
        </div>
      </div>
    </div>
  );
};

export default Nav;
